// MARK: - Promo Manager

@MainActor
final class PromoManager: ObservableObject {
    static let shared = PromoManager()

    @Published private(set) var userAccount: UserAccount
    @Published private(set) var lastHandledURL: URL?
    @Published private(set) var lastResultStatus: String = "Idle"
    @Published private(set) var lastErrorMessage: String?

    private let accountStore: UserAccountStore
    private let promoService: PromoService

    private init(accountStore: UserAccountStore = .shared,
                 promoService: PromoService = .shared) {
        self.accountStore = accountStore
        self.promoService = promoService
        self.userAccount = accountStore.loadCurrentUser()
    }

    func handleIncomingURL(_ url: URL) {
        lastHandledURL = url
        lastErrorMessage = nil

        guard PromoUniversalLinkParser.isSupportedPromoURL(url) else {
            lastResultStatus = "Ignored (not a promo link)"
            return
        }

        do {
            let promo = try PromoUniversalLinkParser.parse(url)
            lastResultStatus = "Parsed promo: \(promo.code) (\(promo.discountPercent)%)"
            applyPromoToCurrentUser(promo)
        } catch {
            lastResultStatus = "Failed"
            lastErrorMessage = (error as? LocalizedError)?.errorDescription ?? String(describing: error)
        }
    }

    func clearPromo() {
        userAccount.appliedPromoCode = nil
        userAccount.appliedDiscountPercent = nil
        userAccount.lastPromoAppliedAt = nil
        accountStore.saveCurrentUser(userAccount)
        lastResultStatus = "Cleared promo"
        lastErrorMessage = nil
    }

    private func applyPromoToCurrentUser(_ promo: Promo) {
        do {
            let updated = try promoService.apply(promo: promo, to: userAccount)
            userAccount = updated
            accountStore.saveCurrentUser(updated)
            lastResultStatus = "Applied to user \(updated.userId)"
        } catch {
            lastResultStatus = "Apply failed"
            lastErrorMessage = (error as? LocalizedError)?.errorDescription ?? String(describing: error)
        }
    }
}

// MARK: - Parser

enum PromoUniversalLinkParser {
    static func isSupportedPromoURL(_ url: URL) -> Bool {
        guard let host = url.host?.lowercased() else { return false }
        guard host == "myapp.com" || host.hasSuffix(".myapp.com") else { return false }
        return url.path.lowercased() == "/promo"
    }

    static func parse(_ url: URL) throws -> Promo {
        guard let components = URLComponents(url: url, resolvingAgainstBaseURL: false) else {
            throw PromoLinkError.invalidURL
        }

        let items = components.queryItems ?? []
        let code = items.firstValue(for: "code")?.trimmingCharacters(in: .whitespacesAndNewlines)
        let discountString = items.firstValue(for: "discount")?.trimmingCharacters(in: .whitespacesAndNewlines)

        guard let code, !code.isEmpty else { throw PromoLinkError.missingCode }
        guard let discountString, !discountString.isEmpty else { throw PromoLinkError.missingDiscount }
        guard let discount = Int(discountString) else { throw PromoLinkError.invalidDiscount }
        guard (1...100).contains(discount) else { throw PromoLinkError.discountOutOfRange }

        return Promo(code: code, discountPercent: discount, sourceURL: url)
    }
}

private extension Array where Element == URLQueryItem {
    func firstValue(for name: String) -> String? {
        first(where: { $0.name.caseInsensitiveCompare(name) == .orderedSame })?.value
    }
}

// MARK: - Models

struct Promo: Codable, Equatable {
    let code: String
    let discountPercent: Int
    let sourceURL: URL
}

struct UserAccount: Codable, Equatable {
    var userId: String
    var appliedPromoCode: String?
    var appliedDiscountPercent: Int?
    var lastPromoAppliedAt: Date?
}

// MARK: - Services / Storage

final class PromoService {
    static let shared = PromoService()

    func apply(promo: Promo, to user: UserAccount) throws -> UserAccount {
        var updated = user
        updated.appliedPromoCode = promo.code
        updated.appliedDiscountPercent = promo.discountPercent
        updated.lastPromoAppliedAt = Date()
        return updated
    }
}

final class UserAccountStore {
    static let shared = UserAccountStore()

    private let defaults = UserDefaults.standard
    private let key = "currentUserAccount"

    func loadCurrentUser() -> UserAccount {
        if let data = defaults.data(forKey: key),
           let user = try? JSONDecoder().decode(UserAccount.self, from: data) {
            return user
        }
        let newUser = UserAccount(userId: Self.generateUserId(), appliedPromoCode: nil, appliedDiscountPercent: nil, lastPromoAppliedAt: nil)
        saveCurrentUser(newUser)
        return newUser
    }

    func saveCurrentUser(_ user: UserAccount) {
        if let data = try? JSONEncoder().encode(user) {
            defaults.set(data, forKey: key)
        }
    }

    private static func generateUserId() -> String {
        if let existing = UserDefaults.standard.string(forKey: "generatedUserId") {
            return existing
        }
        let id = UUID().uuidString
        UserDefaults.standard.set(id, forKey: "generatedUserId")
        return id
    }
}

// MARK: - Errors

enum PromoLinkError: Error, LocalizedError {
    case invalidURL
    case missingCode
    case missingDiscount
    case invalidDiscount
    case discountOutOfRange

    var errorDescription: String? {
        switch self {
        case .invalidURL: return "Invalid URL."
        case .missingCode: return "Missing promo code parameter (code)."
        case .missingDiscount: return "Missing discount parameter (discount)."
        case .invalidDiscount: return "Discount must be an integer."
        case .discountOutOfRange: return "Discount must be between 1 and 100."
        }
    }
}